import org.springframework.context.annotation.*;
import org.springframework.web.client.RestTemplate;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.*;

@Configuration
public class ServiceConfig {
    @Bean
    public RestTemplate restTemplate() {
        return new RestTemplate();
    }
}

@Service
public class OrderToPaymentClient {
    private final RestTemplate restTemplate;

    // k8s DNS: service-name.namespace.svc.cluster.local
    // Or short form if same namespace: http://payment-service
    @Value('${payment.service.url:http://payment-service.payments.svc.cluster.local}')
    private String paymentServiceUrl;

    OrderToPaymentClient(RestTemplate r) { restTemplate = r; }

    public String chargePayment(String orderId, double amount) {
        // k8s ClusterIP service receives this request
        // kube-proxy: round-robin across all healthy payment-service pods
        String url = paymentServiceUrl + '/api/payments';
        return restTemplate.postForObject(url,
            new PaymentRequest(orderId, amount), String.class);
    }

    record PaymentRequest(String orderId, double amount) {}
}

// k8s DNS resolution:
// http://payment-service                    → same namespace
// http://payment-service.payments           → explicit namespace
// http://payment-service.payments.svc.cluster.local → fully qualified
//
// k8s LOAD BALANCING (kube-proxy iptables mode):
// ClusterIP Service → iptables rules → random pod selection
// ECMP (Equal Cost Multi-Path): roughly equal distribution
// Healthier: use Istio service mesh for proper load balancing metrics

