import org.springframework.boot.actuate.health.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// application.yml for k8s probes:
// management:
//   health:
//     probes:
//       enabled: true    # enables /actuator/health/readiness and /liveness
//     livenessState:
//       enabled: true
//     readinessState:
//       enabled: true
//   endpoint:
//     health:
//       group:
//         readiness:
//           include: readinessState,db,redis  # traffic gate
//         liveness:
//           include: livenessState             # restart trigger

// WHY DB FAILURE ≠ LIVENESS FAILURE:
// Liveness probe: should only fail if the application is fundamentally broken
// (deadlocked, out of memory, corrupted state).
// DB down: the app is still running correctly! It just has an unavailable dependency.
// If DB down triggers liveness: k8s restarts the pod.
// Restarted pod: still can't reach the DB (DB is still down!).
// Result: infinite restart loop (CrashLoopBackOff) while DB recovers.
// Correct approach:
//   DB down → readiness probe FAILS (no new traffic)
//   App stays running → when DB recovers → readiness passes → traffic resumes
//   No restarts needed!

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.RANDOM_PORT)
class K8sProbeTest {
    @Autowired WebTestClient wc;
    @Test void readinessEndpoint_available() {
        wc.get().uri('/actuator/health/readiness')
          .exchange().expectStatus().is2xxSuccessful();
    }
    @Test void livenessEndpoint_available() {
        wc.get().uri('/actuator/health/liveness')
          .exchange().expectStatus().is2xxSuccessful();
    }
}

// k8s/payment-deployment.yml (comments only — YAML not Java):
// Deployment: replicas=3, maxSurge=1, maxUnavailable=0
// Resources: requests=512Mi/250m, limits=768Mi/500m
// readinessProbe: /actuator/health/readiness, initialDelay=30
// livenessProbe: /actuator/health/liveness, initialDelay=60

// k8s/payment-service.yml:
// ClusterIP, port 80 → 8080, selector app: payment-service

// k8s/payment-hpa.yml:
// scaleTarget: payment-service Deployment
// minReplicas: 2, maxReplicas: 10
// CPU target: 60% utilization

// application.yml:
// management.health.probes.enabled: true
// liveness includes: livenessState
// readiness includes: readinessState,db,redis

import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class RazorpayK8sTest {
    @Autowired WebTestClient wc;

    @Test void readiness_returnsUp() {
        wc.get().uri('/actuator/health/readiness')
          .exchange().expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }

    @Test void liveness_returnsUp() {
        wc.get().uri('/actuator/health/liveness')
          .exchange().expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }
}

