import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import org.springframework.boot.test.context.SpringBootTest.WebEnvironment;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment=WebEnvironment.RANDOM_PORT)
class ZerodhaK8sSynthesisTest {
    @Autowired WebTestClient wc;

    @Test void readiness_available(){
        wc.get().uri('/actuator/health/readiness')
          .exchange().expectStatus().is2xxSuccessful();
    }
    @Test void liveness_available(){
        wc.get().uri('/actuator/health/liveness')
          .exchange().expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }
    @Test void prometheus_available(){
        wc.get().uri('/actuator/prometheus')
          .exchange().expectStatus().isOk()
          .expectBody(String.class)
          .value(body -> org.junit.jupiter.api.Assertions.assertTrue(
              body.contains('jvm_memory'), 'Should contain jvm metrics'));
    }
}
